417	public function buildUpsellProductDetail(int $customerId, int $productId): JsonResponse
418	{
419	    // 1. Product basic info
420	    $product = DB::table('products')->whereNull('deleted_at')
421	        ->where('id', $productId)->first();
422	
423	    // 2. Feature catalog (ref §3.4: guard TỪNG BẢNG riêng biệt)
424	    $featureGroups = [];
425	    $hasFeatureGroupsTable = $this->support->hasTable('product_feature_groups');
426	    $hasFeaturesTable = $this->support->hasTable('product_features');
427	
428	    if ($hasFeatureGroupsTable) {
429	        $catalogProductIds = $this->resolveCatalogProductIds($productId);
430	        $groups = DB::table('product_feature_groups')
431	            ->whereIn('product_id', $catalogProductIds)
432	            ->orderBy('display_order')->get();
433	
434	        $featureGroups = $groups->map(function ($g) use ($hasFeaturesTable) {
435	            $features = [];
436	            if ($hasFeaturesTable) {
437	                $features = DB::table('product_features')
438	                    ->where('group_id', $g->id)
439	                    ->where('status', 'ACTIVE')
440	                    ->orderBy('display_order')->get()
441	                    ->map(fn ($f) => [
442	                        'feature_name' => $f->feature_name,
443	                        'detail_description' => $f->detail_description ?? null,
444	                    ])->toArray();
445	            }
446	            return [
447	                'id' => $g->id,
448	                'group_name' => $g->group_name,  // khớp UpsellFeatureGroup.group_name
449	                'features' => $features,  // [] nếu bảng product_features thiếu
450	            ];
451	        })->toArray();
452	    }
453	    // Nếu product_feature_groups cũng thiếu → featureGroups = [] (theo §3.4)
454	
455	    // 3. Sector-matched customers with contract value
456	    $customer = DB::table('customers')->where('id', $customerId)->first();
457	    $sectorCustomers = $this->buildDetailedSectorCustomers($customerId, $productId, $customer);
458	
459	    // 4. Target segment info (sales_notes cho SP này + segment KH)
460	    $segmentMatch = $this->findMatchingSegment($customerId, $productId);
461	
462	    return response()->json(['data' => [
463	        'product' => [...],
464	        'feature_groups' => [...],
465	        'sector_customers' => [...],
466	        'segment_match' => $segmentMatch,  // { priority, sales_notes, match_criteria }
467	    ]]);
468	}
